import { readFileSync, writeFileSync } from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const repoRoot = path.resolve(__dirname, '../..')
const configPath = path.join(repoRoot, 'shared', 'tracker-config.json')
const outputPath = path.join(repoRoot, 'ios', 'PuckTracker', 'Sources', 'SharedTrackerConfig.swift')

const config = JSON.parse(readFileSync(configPath, 'utf8'))

const swift = `// Generated by game/scripts/generate-shared-swift-config.mjs.
// Do not edit by hand.

import Foundation
import CoreGraphics

enum SharedTrackerConfig {
    enum LaneBoundaries {
        static let leftMax: CGFloat = ${config.laneBoundaries.leftMax}
        static let deadZoneLeft: CGFloat = ${config.laneBoundaries.deadZoneLeft}
        static let deadZoneRight: CGFloat = ${config.laneBoundaries.deadZoneRight}
        static let rightMin: CGFloat = ${config.laneBoundaries.rightMin}
    }

    enum DekeThresholds {
        static let enter: CGFloat = ${config.dekeThresholds.enter}
        static let exit: CGFloat = ${config.dekeThresholds.exit}
    }

    enum WebSocket {
        static let port = ${config.webSocket.port}
        static let trackerPath = "${config.webSocket.trackerPath}"
        static let gamePath = "${config.webSocket.gamePath}"
    }

    enum MessageTypes {
        static let input = "${config.messageTypes.input}"
        static let state = "${config.messageTypes.state}"
    }
}
`

writeFileSync(outputPath, swift)
